const now = new Date();
const year = now.getUTCFullYear();
const month = String(now.getUTCMonth() + 1).padStart(2, '0');
const reportMonth = `${year}-${month}-01`;
return [{ json: { report_month: reportMonth } }];

const userId = $('Get Users With Pricing Pages').item.json.user_id;
const reportMonth = $('Compute Month').item.json.report_month;
const snapshots = $('Get Latest Snapshots').all().map(i => i.json);

if (!snapshots || snapshots.length === 0) {
  return [{ json: { skip: true, user_id: userId, report_month: reportMonth } }];
}

// --- Helper: map pricing_model string to canonical value_metric ---
function mapValueMetric(pricingModel) {
  if (!pricingModel) return 'unknown';
  const pm = pricingModel.toLowerCase().trim();
  if (pm.includes('seat') || pm.includes('per user') || pm.includes('per-user')) return 'seat';
  if (pm.includes('usage') || pm.includes('consumption') || pm.includes('metered')) return 'usage';
  if (pm.includes('flat') || pm.includes('fixed')) return 'flat';
  if (pm.includes('hybrid') || pm.includes('mixed') || pm.includes('seat') && pm.includes('usage')) return 'hybrid';
  return 'unknown';
}

// --- Helper: parse plan_names into tier_structure ---
function parseTierStructure(planNames) {
  if (!planNames) return [];
  let names = [];
  if (Array.isArray(planNames)) {
    names = planNames;
  } else if (typeof planNames === 'string') {
    try {
      const parsed = JSON.parse(planNames);
      names = Array.isArray(parsed) ? parsed : [planNames];
    } catch {
      names = planNames.split(',').map(s => s.trim()).filter(Boolean);
    }
  }
  return names.map((name, idx) => ({
    name: String(name).trim(),
    position: idx + 1
  }));
}

// --- Helper: parse gating_signals ---
function parseGatingStrategy(gatingSignals) {
  if (!gatingSignals) return {};
  if (typeof gatingSignals === 'object' && !Array.isArray(gatingSignals)) return gatingSignals;
  if (typeof gatingSignals === 'string') {
    try {
      return JSON.parse(gatingSignals);
    } catch {
      return {};
    }
  }
  return {};
}

// --- Build landscape entries ---
const landscapeEntries = snapshots.map(snap => {
  const tierStructure = parseTierStructure(snap.plan_names);
  const valueMetric = mapValueMetric(snap.pricing_model);
  const gatingStrategy = parseGatingStrategy(snap.gating_signals);

  return {
    user_id: userId,
    company_id: snap.company_id,
    company_name: snap.company_name,
    tier_structure: JSON.stringify(tierStructure),
    value_metric: valueMetric,
    gating_strategy: JSON.stringify(gatingStrategy),
    pricing_url: snap.pricing_url,
    plan_count: snap.plan_count || tierStructure.length,
    has_free_tier: snap.has_free_tier || false,
    has_enterprise: snap.has_enterprise || false,
    snapshot_date: snap.snapshot_date
  };
});

// --- Trend detection ---
const totalCompanies = landscapeEntries.length;
const metricCounts = { seat: 0, usage: 0, flat: 0, hybrid: 0, unknown: 0 };
let freeTierCount = 0;
let enterpriseCount = 0;
let totalPlans = 0;

landscapeEntries.forEach(entry => {
  metricCounts[entry.value_metric] = (metricCounts[entry.value_metric] || 0) + 1;
  if (entry.has_free_tier) freeTierCount++;
  if (entry.has_enterprise) enterpriseCount++;
  totalPlans += entry.plan_count;
});

const avgPlanCount = totalCompanies > 0 ? Math.round((totalPlans / totalCompanies) * 10) / 10 : 0;
const freeTierPct = totalCompanies > 0 ? Math.round((freeTierCount / totalCompanies) * 100) : 0;
const enterprisePct = totalCompanies > 0 ? Math.round((enterpriseCount / totalCompanies) * 100) : 0;

// Determine dominant pricing model
const dominantMetric = Object.entries(metricCounts)
  .filter(([k]) => k !== 'unknown')
  .sort((a, b) => b[1] - a[1])[0];
const dominantPct = dominantMetric && totalCompanies > 0
  ? Math.round((dominantMetric[1] / totalCompanies) * 100)
  : 0;

// Detect category-wide trends
const trends = [];
let categoryShift = false;

if (dominantMetric && dominantPct >= 60) {
  trends.push({
    type: 'dominant_model',
    detail: `${dominantPct}% of tracked competitors use ${dominantMetric[0]}-based pricing`,
    significance: 'high'
  });
}

if (metricCounts.usage > 0 && metricCounts.usage >= totalCompanies * 0.4) {
  trends.push({
    type: 'usage_adoption',
    detail: `${Math.round((metricCounts.usage / totalCompanies) * 100)}% have adopted usage-based pricing — signals category shift toward consumption models`,
    significance: 'high'
  });
  categoryShift = true;
}

if (freeTierPct >= 70) {
  trends.push({
    type: 'free_tier_standard',
    detail: `${freeTierPct}% of competitors offer a free tier — free has become table stakes`,
    significance: 'medium'
  });
} else if (freeTierPct <= 20 && totalCompanies >= 3) {
  trends.push({
    type: 'free_tier_rare',
    detail: `Only ${freeTierPct}% offer a free tier — market prefers gated entry`,
    significance: 'medium'
  });
}

if (enterprisePct >= 80) {
  trends.push({
    type: 'enterprise_tier_universal',
    detail: `${enterprisePct}% include an enterprise tier — upmarket motion is dominant`,
    significance: 'medium'
  });
}

if (avgPlanCount >= 5) {
  trends.push({
    type: 'tier_proliferation',
    detail: `Average plan count is ${avgPlanCount} — competitors are micro-segmenting`,
    significance: 'low'
  });
}

// If more than one high-significance trend, flag category shift
const highTrends = trends.filter(t => t.significance === 'high');
if (highTrends.length >= 2) categoryShift = true;

// --- Build landscape map ---
const companiesIncluded = landscapeEntries.map(e => e.company_name);
const title = `Packaging Landscape \u2014 ${reportMonth.substring(0, 7)}`;

const contentJson = JSON.stringify({
  total_companies: totalCompanies,
  avg_plan_count: avgPlanCount,
  free_tier_pct: freeTierPct,
  enterprise_pct: enterprisePct,
  metric_distribution: metricCounts,
  trend_count: trends.length,
  category_shift: categoryShift
});

// Markdown summary
const trendsMd = trends.length > 0
  ? trends.map(t => `- **[${t.significance.toUpperCase()}]** ${t.detail}`).join('\\n')
  : '- No significant category-wide trends detected this month.';

const companyListMd = landscapeEntries.map(e => {
  const ft = e.has_free_tier ? 'Yes' : 'No';
  const ent = e.has_enterprise ? 'Yes' : 'No';
  return `| ${e.company_name} | ${e.plan_count} | ${e.value_metric} | ${ft} | ${ent} |`;
}).join('\\n');

const contentMd = `# ${title}\\n\\n**Report Month:** ${reportMonth}\\n**Companies Tracked:** ${totalCompanies}\\n**Average Plans Per Company:** ${avgPlanCount}\\n\\n---\\n\\n## Pricing Model Distribution\\n- Seat-based: ${metricCounts.seat}\\n- Usage-based: ${metricCounts.usage}\\n- Flat-rate: ${metricCounts.flat}\\n- Hybrid: ${metricCounts.hybrid}\\n- Unknown: ${metricCounts.unknown}\\n\\n## Key Metrics\\n- Free tier adoption: ${freeTierPct}%\\n- Enterprise tier adoption: ${enterprisePct}%\\n\\n## Trends\\n${trendsMd}\\n\\n## Company Landscape\\n| Company | Plans | Metric | Free Tier | Enterprise |\\n|---------|-------|--------|-----------|------------|\\n${companyListMd}\\n\\n---\\n*Generated by Signal Plane Packaging Landscape Monitor*`;

// --- Emit output items ---
// Each landscape entry becomes a separate output item for the upsert node,
// plus the map data and category_shift flag are attached to each.
const output = landscapeEntries.map(entry => ({
  json: {
    ...entry,
    report_month: reportMonth,
    title: title,
    content_json: contentJson,
    content_md: contentMd,
    trends: JSON.stringify(trends),
    companies_included: companiesIncluded,
    category_shift: categoryShift
  }
}));

return output;
